here's some code snippets outlining how to do the same things with the old resource and the new resource if the new resource just returns a snowflake SnowflakeConnection 

```
@asset(
    required_resource_keys={"snowflake"}
)
def run_query_old(context):
    snowflake = context.resources.snowflake
    snowflake.execute_query("SELECT 1", fetch_results=True, use_pandas_result=True)

@asset
def run_query_new(snowflake: SnowflakeResource):
    with snowflake.get_connection() as conn:
        conn.cursor().execute("SELECT 1").fetch_pandas_all()


@asset(
    required_resource_keys={"snowflake"}
)
def run_queries_old(context):
    snowflake = context.resources.snowflake
    results = snowflake.execute_queries(["SELECT 1", "SELECT 2", "SELECT 3"], fetch_results=True, use_pandas_result=True)

@asset
def run_queries_new(snowflake: SnowflakeResource):
    queries = ["SELECT 1", "SELECT 2", "SELECT 3"]
    results = []
    with snowflake.get_connection() as conn:
        for q in queries:
            results.append(conn.cursor().execute(q).fetch_pandas_all())
```

